INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0604014N$$, 2027, $$The AN/ASG-34A(V)1 F/A-18E/F Infrared Search and Track (IRST) system is a long-wave infrared sensor that provides a passive, out-of-band, alternate fire control
system capable of detecting, tracking and engaging airborne targets, at long range, in a heavy electronic attack or radar-denied environment. IRST Block II is the primary
out-of-band fire-control system for the F/A-18E/F, critical to organic passive air-to-air kill-chains required to compete with peer adversaries. Enables F/A-18E/F lethality
by providing a passive means to detect, track, and target aircraft in highly contested environments in support of the objectives outlined in the National Defense Strategy.
IRST enhances survivability by providing a fire-control solution without the need to radiate in the RF spectrum. The IRST system can autonomously, or in combination
with other sensors, support the guidance of beyond-visual-range missiles including AIM-120C/D and AIM-9X Block II. The F/A-18E/F IRST system is an evolutionary
Navy acquisition program with Block I and Block II capabilities. The USN is committed to further development of this component of the passive kill chain.

 This budget request supports Block II development and testing of a redesigned Infrared Receiver (IRR) and processor, enabling full Capabilities Development Document
 (CDD) capability over a larger field of regard.$$, $$The AN/ASG-34A(V)1 F/A-18E/F Infrared Search and Track (IRST) system is a long-wave infrared sensor that provides a passive, out-of-band, alternate fire control
system capable of detecting, tracking and engaging airborne targets, at long range, in a heavy electronic attack or radar-denied environment. IRST Block II is the primary
out-of-band fire-control system for the F/A-18E/F, critical to organic passive air-to-air kill-chains required to compete with peer adversaries. Enables F/A-18E/F lethality
by providing a passive means to detect, track, and target aircraft in highly contested environments in support of the objectives outlined in the National Defense Strategy.
IRST enhances survivability by providing a fire-control solution without the need to radiate in the RF spectrum. The IRST system can autonomously, or in combination
with other sensors, support the guidance of beyond-visual-range missiles including AIM-120C/D and AIM-9X Block II. The F/A-18E/F IRST system is an evolutionary
Navy acquisition program with Block I and Block II capabilities. The USN is committed to further development of this component of the passive kill chain.

 This budget request supports Block II development and testing of a redesigned Infrared Receiver (IRR) and processor, enabling full Capabilities Development Document
 (CDD) capability over a larger field of regard.

B. Accomplishments/Planned Programs ($ in Millions, Article Quantities in Each)                                                               FY 2027 FY 2027 FY 2027
                                                                                                                     FY 2025 FY 2026           Base    OOC     Total
Title: Infra-Red Search and Track (IRST)                                                                                8.556   0.000            0.000   0.000   0.000
