INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0604454N$$, 2027, $$LPD 17 Flight II will replace LSD 41 Class ships and LSD 49 Class ships for embark, transport, control, insert, sustainment, and extract of Marine Air-Ground Task Force
elements and supporting forces by helicopters, landing craft, and amphibious vehicles. This project includes efforts to reduce the cost of building and repairing ships,
resolving obsolescence issues, and improving shipbuilding industry productivity through: advanced technology and processes with emphasis towards developing ship
hull, mechanical, propulsion, electrical, aviation, warfare system, combat support system, sub-systems and components to maintain manpower, survivability, operational
capabilities, and pursue affordability initiatives. This program element includes the planning & documentation for Developmental Test and Evaluation (DT&E), Live Fire
Test & Evaluation (LFT&E), Operational Evaluation (OPEVAL), and Follow-on Operational Test and Evaluation (FOT&E) tests required for LPD 17 Flight II. These test
events will be conducted on the lead Flight II Ship (LPD 30) or where configuration supports capabilities on LPD 29. The test events will be conducted as needed on
Flight II follow ships (LPD 31/32) for verification of correction of deficiencies (VCD) from the lead Flight II Ship (LPD 30) as well as design/system changes.$$, $$LPD 17 Flight II will replace LSD 41 Class ships and LSD 49 Class ships for embark, transport, control, insert, sustainment, and extract of Marine Air-Ground Task Force
elements and supporting forces by helicopters, landing craft, and amphibious vehicles. This project includes efforts to reduce the cost of building and repairing ships,
resolving obsolescence issues, and improving shipbuilding industry productivity through: advanced technology and processes with emphasis towards developing ship
hull, mechanical, propulsion, electrical, aviation, warfare system, combat support system, sub-systems and components to maintain manpower, survivability, operational
capabilities, and pursue affordability initiatives. This program element includes the planning & documentation for Developmental Test and Evaluation (DT&E), Live Fire
Test & Evaluation (LFT&E), Operational Evaluation (OPEVAL), and Follow-on Operational Test and Evaluation (FOT&E) tests required for LPD 17 Flight II. These test
events will be conducted on the lead Flight II Ship (LPD 30) or where configuration supports capabilities on LPD 29. The test events will be conducted as needed on
Flight II follow ships (LPD 31/32) for verification of correction of deficiencies (VCD) from the lead Flight II Ship (LPD 30) as well as design/system changes.

